//vip.opstream14.com/share/693d963c5bc8ff46b4351667b3c4a663","link_m3u8":"https://vip.opstream14.com/20230318/33813_fc4f4d15/index.m3u8"}]}],"time":"45 phút/tập","description":"<p>Hai nàng công chúa sinh đôi với tính cách đối lập. Nếu tỷ tỷ Ly Quang Thanh Quỳ là người lương thiện ấm áp, tài mạo song toàn và là điềm may của cả gia tộc, thì muội muội Ly Quang Dạ Đàm lại được coi là điềm gở khi có tính cách bướng bỉnh, dữ dằn và chuyên phá hỏng mọi chuyện. Thanh Quỳ vốn được định gả cho Thiên tộc, còn Dạ Đàm sẽ về làm dâu Ma tộc.&nbsp; Nhưng một sự cố trên đường đưa dâu đã khiến Thanh Quỳ lương thiện phải bước chân vào Ma tộc khát máu tàn bạo làm vợ hoàng tử Triều Phong. Dạ Đàm cá tính mạnh mẽ lại trở thành cô dâu Thiên tộc, vợ của thái tử Thiếu Điển Hữu Cầm.</p>","tmdb":{"type":"tv","id":"196157","season":1,"vote_average":7.1,"vote_count":16},"modified":"2023-03-18T10:41:23.000Z","_image_preserved":true},{"id":"63ee547e06abbba8eef96fa6","_id":"63ee547e06abbba8eef96fa6","title":"Bạn Gái Nhà Kế","origin_name":"The Woman Next Door","slug":"ban-gai-nha-ke","year":1981,"type":"single","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"},{"id":"620f3d2b91fa4af90ab697fe","name":"Chính kịch","slug":"chinh-kich"}],"country":[{"id":"620a2378e0fc277084dfd972","name":"Pháp","slug":"phap"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"The Woman Next Door - 1981","link_embed":"https://vip.opstream14.com/share/7ffa844678e10a4551300dedcbabb52d","link_m3u8":"https://vip.opstream14.com/20230216/31967_c2db70db/index.m3u8"}]}],"time":"106 Phút","description":"<p>Bà Jouve, người kể chuyện, kể về bi kịch của Bernard và Mathilde. Bernard đang sống hạnh phúc với vợ Arlette và cậu con trai Thomas. Một ngày nọ, một cặp vợ chồng Philippe và Mathilde Bauchard chuyển đến ngôi nhà bên cạnh. Đây là cuộc hội ngộ tình cờ của Bernard và Mathilde, hai người đã có một mối tình say đắm nhiều năm trước. Mối quan hệ hồi sinh... Một nghiên cứu ảm đạm về cảm xúc của con người.</p>","tmdb":{"type":"movie","id":"12579","season":null,"vote_average":7.1,"vote_count":328},"modified":"2023-02-16T23:06:22.000Z","_image_preserved":true},{"id":"63ee557106abbba8eef99381","_id":"63ee557106abbba8eef99381","title":"Tay Chuyên Nghiệp","origin_name":"The Professional","slug":"tay-chuyen-nghiep","year":1981,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"},{"id":"620a2293e0fc277084dfd489","name":"Phiêu Lưu","slug":"phieu-luu"},{"id":"620f84d291fa4af90ab6b3f4","name":"Bí ẩn","slug":"bi-an"}],"country":[{"id":"620a2378e0fc277084dfd972","name":"Pháp","slug":"phap"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"The Professional - 1981","link_embed":"https://vip.opstream14.com/share/3f41d2337b29507d20a2fdd7f8305110","link_m3u8":"https://vip.opstream14.com/20230216/31962_612da421/index.m3u8"}]}],"time":"108 Phút","description":"<p>Đặc vụ mật vụ Pháp Josselin Beaumont được cử đi tiêu diệt lãnh chúa châu Phi N'Jala. Nhưng khi nhiệm vụ của anh ấy bị hủy bỏ, anh ấy bị sốc khi biết rằng chính phủ của anh ấy đang giao nộp anh ấy cho chính quyền địa phương. Anh ta bị đưa ra một phiên tòa giả và bị kết án 20 năm lao động khổ sai. Nhưng Beaumont trốn thoát khỏi nhà tù và thề không chỉ trả thù những kẻ phản bội mình mà còn hoàn thành nhiệm vụ ban đầu.</p>","tmdb":{"type":"movie","id":"1672","season":null,"vote_average":7.2,"vote_count":560},"modified":"2023-02-16T23:10:25.000Z","_image_preserved":true},{"id":"63ee563d06abbba8eef9af7d","_id":"63ee563d06abbba8eef9af7d","title":"Bầy Quỷ","origin_name":"The Brood","slug":"bay-quy","year":1979,"type":"single","genre":[{"id":"620a2282e0fc277084dfd435","name":"Viễn Tưởng","slug":"vien-tuong"},{"id":"620a22ace0fc277084dfd531","name":"Kinh Dị","slug":"kinh-di"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"The Brood - 1979","link_embed":"https://vip.opstream14.com/share/689b243e8f33e0d27343ebb0d83b513a","link_m3u8":"https://vip.opstream14.com/20230216/31959_867d30f9/index.m3u8"}]}],"time":"92 Phút","description":"<p>Một người đàn ông cố gắng khám phá các kỹ thuật trị liệu độc đáo của nhà tâm lý học đối với người vợ được đưa vào viện dưỡng lão của mình, trong khi một loạt vụ tấn công tàn bạo do một đàn con đột biến gây ra trùng khớp với cuộc điều tra của người chồng.</p>","tmdb":{"type":"movie","id":"28942","season":null,"vote_average":6.719,"vote_count":772},"modified":"2023-02-16T23:13:49.000Z","_image_preserved":true},{"id":"63ee56ec06abbba8eef9c59b","_id":"63ee56ec06abbba8eef9c59b","title":"Lính Bắn Tỉa 2","origin_name":"Sniper 2","slug":"linh-ban-tia-2","year":2002,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Sniper 2 - 2002","link_embed":"https://vip.opstream14.com/share/5f447df2f1d70893e3805f3dab9183c4","link_m3u8":"https://vip.opstream14.com/20230216/31958_931bb47e/index.m3u8"}]}],"time":"91 Phút","description":"<p>Trung sĩ Thomas Beckett đã trở lại - và lần này anh đã hợp tác với tử tù B.J. Cole trong một nhiệm vụ liều chết đến vùng Balkan. Mục tiêu của họ: một vị tướng lưu manh bị buộc tội điều hành các nhiệm vụ thanh trừng sắc tộc. Nhưng khi Becket phát hiện ra rằng chính phủ đang sử dụng anh ta như một con tốt trong một nhiệm vụ lớn hơn, số lượng cơ thể tăng lên và đạn thực sự bắt đầu bay.</p>","tmdb":{"type":"movie","id":"14245","season":null,"vote_average":5.5,"vote_count":154},"modified":"2023-02-16T23:16:44.000Z","_image_preserved":true},{"id":"63ee579806abbba8eef9da6c","_id":"63ee579806abbba8eef9da6c","title":"Scary Movie 4","origin_name":"Scary Movie 4","slug":"scary-movie-4","year":2006,"type":"single","genre":[{"id":"620a221de0fc277084dfd1c1","name":"Hài Hước","slug":"hai-huoc"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Scary Movie 4 - 2006","link_embed":"https://vip.opstream14.com/share/8e9240a9f16db317677aa70bfeb6f560","link_m3u8":"https://vip.opstream14.com/20230216/31957_fc5fd58d/index.m3u8"}]}],"time":"83 Phút","description":"<p>Cindy phát hiện ra ngôi nhà cô đang sống bị ám bởi một cậu bé và bắt đầu hành trình tìm ra kẻ đã giết cậu bé và tại sao. Ngoài ra, \"Tr-iPod\" ngoài hành tinh đang xâm chiếm thế giới và cô ấy phải khám phá ra bí mật để ngăn chặn chúng.</p>","tmdb":{"type":"movie","id":"4257","season":null,"vote_average":5.491,"vote_count":3425},"modified":"2023-02-16T23:20:14.000Z","_image_preserved":true},{"id":"63ee588906abbba8eef9ffbd","_id":"63ee588906abbba8eef9ffbd","title":"Vương Quốc Dục Cảm","origin_name":"In the Realm of the Senses","slug":"vuong-quoc-duc-cam","year":1976,"type":"single","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"},{"id":"620f3d2b91fa4af90ab697fe","name":"Chính kịch","slug":"chinh-kich"}],"country":[{"id":"620a2307e0fc277084dfd726","name":"Nhật Bản","slug":"nhat-ban"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"In the Realm of the Senses - 1976","link_embed":"https://vip.opstream14.com/share/88083dbfcee5080bb9f38e21107efd08","link_m3u8":"https://vip.opstream14.com/20230216/31956_0f9e70e9/index.m3u8"}]}],"time":"105 Phút","description":"<p>Bộ phim dựa trên một câu chuyện có thật xảy ra trước thế chiến thứ 2 ở Nhật, về một cuộc tình ám ảnh giữa một người đàn ông ( Kichizo ) và cô hầu trong nhà ( Sada ). Sada càng lúc càng trở nên lấn tới, điều khiển từng động tác \"kĩ thuật\" làm tình. Hai nhân vật chính trong phim mây mưa không ngừng nghỉ, với nhiều \"chiêu bài\" mới lạ để đạt được sự thỏa mãn tột đỉnh, kể cả đánh đập, thắt cổ nhau. Không chỉ dừng ở mức quay rõ cảnh khỏa thân, giao hợp rõ mồn một mà cả những hình ảnh kích thích tình dục qua đường miệng cũng không hề chút che đậy ! Hình ảnh kết thúc phim chìm trong hoan lạc và bạo động, có thể khiến khán giả phải chóng mặt !</p>","tmdb":{"type":"movie","id":"5879","season":null,"vote_average":6.59,"vote_count":686},"modified":"2023-02-16T23:23:37.000Z","_image_preserved":true},{"id":"63ee5a1f06abbba8eefa359b","_id":"63ee5a1f06abbba8eefa359b","title":"Fame","origin_name":"Fame","slug":"fame","year":2009,"type":"single","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"},{"id":"620a221de0fc277084dfd1c1","name":"Hài Hước","slug":"hai-huoc"},{"id":"620a22bae0fc277084dfd585","name":"Âm Nhạc","slug":"am-nhac"},{"id":"620f3d2b91fa4af90ab697fe","name":"Chính kịch","slug":"chinh-kich"}],"country":[{"id":"6